code.perVertex:
w= -time*0.3; // direction (0: left; asin(1): top; (+/-)2*asin(1): right; -asin(1): bottom);
X2 = x-0.5;;
Y2 = y-0.5;;
X1 = sin(w)*X2 -cos(w)*Y2; // these 2 lines first rotate the x/y pane;
Y1 = cos(w)*X2 +sin(w)*Y2;;
x = X1; // so you can use x and y as usually below;
y = Y1;;
//Tiles-;
//movement first:;
dxm=.01*sin(time*.41);;
dym=.01*sin(time*.36);;
//Now the tiles themselves:;
dx1=dxm+.01*sin(x*80+sin(time))+.005*sin(q1*(y*sin(time*.94)));;
dy1=dym+.01*sin(y*80+sin(time))+.005*sin(q1*(x*sin(time*.97)));;
//end tiles;
dx = sin(-w)*dx1 - cos(-w)*dy1; // and finally the dx/dy pane is rotated back to match the x/y pane;
dy = cos(-w)*dx1 + sin(-w)*dy1;
